options.css:
@import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@600;700;800;900&display=swap');

:root{
  --bt-accent:#58a6ff;
  --bt-accent2:#7dc4ff;

  --bt-ok:#22c55e;
  --bt-bad:#ff5c5c;
  --bt-warn:#f6c445;

  --bt-text:#eaf3ff;

  --bt-panel-border: rgba(88,166,255,0.22);
  --bt-panel-bg1: rgba(18,36,60,0.88);
  --bt-panel-bg2: rgba(10,20,36,0.92);
  --bt-panel-topglow: rgba(10,20,36,0.92);
  --bt-soft-line: rgba(255,255,255,0.08);
  --bt-card-bg: rgba(10,20,36,0.92);
  --bt-input-bg: rgba(10,18,30,0.82);
}

html, body{
  margin:0;
  padding:0;
  width:100%;
  height:100%;
  background: radial-gradient(circle at top left, rgba(36,78,138,.18), transparent 28%),
              linear-gradient(180deg, #07111c 0%, #0a1624 100%);
  color:var(--bt-text);
  font-family:"Segoe UI", system-ui, Arial, sans-serif;
}

.bt-layout{
  height:100%;
  display:grid;
  grid-template-columns: 1.85fr 1fr;
  gap:12px;
  color:var(--bt-text);
}

.bt-left{
  height:100%;
  min-height:0;
}

.bt-right{
  height:100%;
  min-height:0;
  display:flex;
  flex-direction:column;
  gap:12px;
}

.panel{
  border-radius:14px;
  border:1px solid var(--bt-panel-border);
  background: linear-gradient(180deg, var(--bt-panel-bg1), var(--bt-panel-bg2)),
              radial-gradient(circle at top, rgba(88,166,255,0.05), transparent 70%);
  box-shadow: 0 12px 26px rgba(0,0,0,0.45), inset 0 0 0 1px rgba(125,196,255,0.05);
  padding:12px;
  overflow:hidden;
  position:relative;
  min-height:0;
}

.panel:before{
  content:"";
  position:absolute;
  left:10px;
  right:10px;
  top:0;
  height:2px;
  background: linear-gradient(90deg, transparent, var(--bt-panel-topglow), transparent);
  opacity:0.75;
}

.bt-detail-header{
  display:flex;
  justify-content:space-between;
  align-items:center;
  margin-bottom:10px;
}
.bt-detail-title{
  font-size:26px;
  font-weight:900;
  letter-spacing:1.6px;
  text-transform:uppercase;
  text-shadow:0 0 12px rgba(88,166,255,0.18);
  font-family:'Orbitron', "Segoe UI", system-ui, sans-serif;
}

.bt-detail-chip{
  display:flex;
  align-items:center;
  gap:10px;
  padding:8px 12px;
  border-radius:12px;
  border:1px solid rgba(88,166,255,0.26);
  background: linear-gradient(180deg, rgba(18,32,52,0.92), rgba(9,16,28,0.92));
}

.chip-label{
  font-weight:900;
  opacity:0.85;
  letter-spacing:1px;
  font-size:12px;
  color:#d8e8ff;
  font-family:'Orbitron', "Segoe UI", system-ui, sans-serif;
}

.chip-value{
  font-weight:900;
  font-size:16px;
  padding:4px 10px;
  border-radius:999px;
  background:rgba(88,166,255,0.14);
  border:1px solid rgba(88,166,255,0.30);
  color:#fff;
  font-family:'Orbitron', "Segoe UI", system-ui, sans-serif;
}

.bt-detail-grid{
  display:grid;
  grid-template-columns: 1fr 1fr;
  gap:12px;
  height:calc(100% - 58px);
  min-height:0;
}

.panel-title{
  font-weight:900;
  letter-spacing:1px;
  text-transform:uppercase;
  font-size:12px;
  opacity:0.95;
  margin-bottom:10px;
  color:#d9e9ff;
  flex:0 0 auto;
  font-family:'Orbitron', "Segoe UI", system-ui, sans-serif;
}

/* ===== tank ===== */
.tank-panel{
  display:flex;
  flex-direction:column;
  gap:10px;
  height:100%;
  min-height:0;
  border-radius:12px;
  background:
    radial-gradient(circle at 45% 25%, rgba(88,166,255,0.05), transparent 70%),
    linear-gradient(180deg, rgba(10,18,30,0.96), rgba(2,8,16,0.99));
}

.tank-hero{
  display:flex;
  justify-content:center;
  align-items:flex-start;
  padding-top:4px;
  margin-bottom:0;
  flex:0 0 auto;
}

.tank-pack{
  display:flex;
  justify-content:center;
  align-items:flex-start;
  gap:12px;
  margin:0 auto;
}

.tank-scale.big{
  position:relative;
  height:175px;
  width:48px;
  font-size:12px;
  color:rgb(210,225,245);
}

.tank-scale.big .tick{ position:absolute; left:0; }
.tank-scale.big .tick-top{ top:0; }
.tank-scale.big .tick-mid{ top:50%; transform:translateY(-50%); }
.tank-scale.big .tick-bottom{ bottom:0; }

.tank-body.big{
  display:flex;
  flex-direction:column;
  align-items:center;
}

.tank-outer.big{
  position:relative;
  width:135px;
  height:195px;
}

.tank-inner.big{
  position:absolute;
  left:0;
  right:0;
  top:0;
  bottom:16px;
  margin:auto;
  border-radius:16px;
  border:2px solid rgba(255,255,255,0.82);
  background: radial-gradient(circle at 30% 0%, #203553 0, #0f1d31 62%, #09111b 100%);
  overflow:hidden;
  box-shadow:0 0 10px rgba(0,0,0,0.65), inset 0 0 14px rgba(0,0,0,0.85), 0 0 18px rgba(88,166,255,0.12);
}

.tank-glass{
  position:absolute;
  top:4%;
  bottom:45%;
  left:10%;
  width:20%;
  border-radius:50px;
  background:linear-gradient(to bottom, rgba(255,255,255,0.20), rgba(255,255,255,0));
}

.tank-band{
  position:absolute;
  left:0;
  right:0;
  bottom:24%;
  height:12%;
  background:rgba(88,166,255,0.10);
}

.tank-fill{
  position:absolute;
  left:0;
  right:0;
  bottom:0;
  height:45%;
  background:linear-gradient(to top, #2d6cdf, #58a6ff 55%, #cfe7ff 100%);
  box-shadow:0 0 14px rgba(88,166,255,0.35), inset 0 3px 10px rgba(255,255,255,0.16);
}

.tank-fill.level-green{
  background:linear-gradient(to top, #118b43, #22c55e 45%, #bbf7d0 100%);
}

.tank-fill.level-yellow{
  background:linear-gradient(to top, #b88900, #f6c445 55%, #fff1b3 100%);
}

.tank-fill.level-red{
  background:linear-gradient(to top, #9f1f1f, #ff5c5c 50%, #ffd4d4 100%);
}

.tank-foot{
  position:absolute;
  bottom:0;
  width:16px;
  height:10px;
  background:linear-gradient(to top, #62758d, #9aabbe);
  border-radius:4px 4px 0 0;
  box-shadow:0 0 6px rgba(0,0,0,0.65);
}

.tank-foot.left{ left:16px; }
.tank-foot.right{ right:16px; }

.tank-zone{
  position:absolute;
  left:12px;
  font-size:10px;
  font-weight:800;
  letter-spacing:.8px;
  opacity:.72;
  color:#edf5ff;
}

.tank-zone.top{ top:10px; }
.tank-zone.mid{ top:48%; transform:translateY(-50%); }
.tank-zone.low{ bottom:24px; }

.tank-readout{
  margin-top:6px;
  text-align:center;
}

.readout-main{
  font-size:34px;
  font-weight:800;
  letter-spacing:.3px;
  color:#ffffff;
}

.readout-unit{
  font-size:14px;
  font-weight:700;
  opacity:.85;
  margin-left:6px;
  color:#d8e8ff;
}

/* ===== KPI ===== */
.kpi-panel{
  display:flex;
  flex-direction:column;
  gap:10px;
  height:100%;
  min-height:0;
  border-radius:12px;
  background:
    radial-gradient(circle at 50% 0%, rgba(88,166,255,0.05), transparent 70%),
    linear-gradient(180deg, rgba(10,18,30,0.96), rgba(2,8,16,0.99));
}

.kpi-grid{
  display:grid;
  grid-template-columns:repeat(2, minmax(0,1fr));
  gap:10px;
  flex:0 0 auto;
}

.kpi-card{
  border-radius:12px;
  padding:10px 12px;
  border:1px solid rgba(20,45,85,0.9);
  background:rgba(6,14,26,0.35);
  min-height:58px;
  font-family:'Orbitron', "Segoe UI", system-ui, sans-serif;
}

.kpi-green{
  border:1px solid rgba(0,219,114,.45);
  background:linear-gradient(180deg, rgba(0,82,52,.22), rgba(0,42,28,.18));
  box-shadow: inset 0 0 0 1px rgba(0,219,114,.06), 0 0 12px rgba(0,219,114,.05);
}

.kpi-label{
  font-size:11px;
  font-weight:900;
  letter-spacing:1px;
  text-transform:uppercase;
  color:#67ffb5;
  margin-bottom:6px;
  font-family:'Orbitron', "Segoe UI", system-ui, sans-serif;
}

.kpi-main{
  display:flex;
  align-items:baseline;
  gap:6px;
  font-weight:800;
  letter-spacing:.15px;
}

.kpi-value{
  font-size:18px;
  font-weight:800;
  color:#f3fbff;
  line-height:1.1;
}

.kpi-unit{
  font-size:12px;
  font-weight:700;
  opacity:.85;
  color:#d4e8ff;
}

/* ===== trends ===== */
.mini-trend{
  margin-top:10px;
  padding-top:10px;
  border-top:1px dashed rgba(255,255,255,0.12);
  display:flex;
  flex-direction:column;
  flex:1;
  min-height:0;
}

.mini-title{
  display:flex;
  justify-content:space-between;
  align-items:center;
  font-size:11px;
  font-weight:800;
  letter-spacing:.7px;
  text-transform:uppercase;
  color:#d9e9ff;
  margin-bottom:8px;
  flex:0 0 auto;
}

.mini-last{
  font-size:11px;
  font-weight:700;
  color:rgba(210,225,245,0.85);
  text-transform:none;
}

.mini-chart{
  flex:1;
  min-height:150px;
  height:100%;
  border-radius:12px;
  border:1px solid rgba(30,60,110,0.75);
  background:rgba(8,16,28,0.92);
  width:96%;
  margin:0 auto;
}
/* ===== right table ===== */
.pcd-head{
  display:flex;
  align-items:center;
  justify-content:space-between;
  gap:12px;
  margin-bottom:10px;
}

.pcd-head-left{
  position:relative;
  padding-left:14px;
}

.pcd-head-left::before{
  content:"";
  position:absolute;
  left:0;
  top:3px;
  bottom:3px;
  width:5px;
  border-radius:999px;
  background:linear-gradient(180deg, rgba(88,166,255,.96), rgba(125,196,255,.90));
}

.pcd-title{
  font-size:18px;
  font-weight:900;
  letter-spacing:1.2px;
  text-transform:uppercase;
  color:#dfe8ff;
  font-family:'Orbitron', "Segoe UI", system-ui, sans-serif;
}

.pcd-search{
  display:flex;
  align-items:center;
  gap:8px;
  border:1px solid rgba(255,255,255,.10);
  background:var(--bt-input-bg);
  border-radius:12px;
  padding:9px 12px;
  min-width:280px;
}

.pcd-search-in{
  width:100%;
  border:0;
  outline:none;
  background:transparent;
  color:#ECF6FF;
  font-size:13px;
}

.pcd-search-ic{
  opacity:.75;
  font-weight:800;
}

.pcd-table-wrap{
  border:1px solid rgba(255,255,255,.08);
  background:rgba(8,14,24,.62);
  border-radius:14px;
  overflow:auto;
}

.pcd-row{
  display:grid;
  align-items:center;
  column-gap:10px;
}

.bulk-cols{
  grid-template-columns: 1.05fr 1.2fr 1.0fr .9fr .8fr .7fr .95fr 1fr;
}

.pcd-table-head{
  padding:12px 12px;
  font-size:11px;
  font-weight:800;
  text-transform:uppercase;
  letter-spacing:.7px;
  color:rgba(220,232,252,.75);
  border-bottom:1px solid rgba(255,255,255,.08);
  position:sticky;
  top:0;
  background:linear-gradient(180deg, rgba(23,31,44,.95), rgba(16,22,34,.94));
  z-index:1;
}

.pcd-item{
  padding:10px 12px;
  border-left:4px solid transparent;
  border-bottom:1px solid rgba(255,255,255,.05);
  min-height:52px;
}

.pcd-item:hover{
  background:rgba(255,255,255,.03);
}

.pcd-item:first-of-type{
  border-left-color:#58a6ff;
}

.pcd-strong{
  font-weight:800;
  color:#f4f8ff;
  font-size:13px;
}

.pcd-dim{
  color:rgba(224,233,247,.78);
  font-size:12px;
}

.pcd-chipval{
  display:inline-flex;
  align-items:center;
  justify-content:center;
  min-width:44px;
  padding:6px 10px;
  border-radius:999px;
  background:rgba(88,166,255,.12);
  border:1px solid rgba(88,166,255,.25);
  color:#ebf5ff;
  font-size:12px;
  font-weight:800;
}

.pcd-state-btn{
  border:0;
  outline:none;
  padding:8px 14px;
  border-radius:999px;
  font-size:11px;
  font-weight:800;
  letter-spacing:.8px;
  cursor:pointer;
  font-family:'Orbitron', "Segoe UI", system-ui, sans-serif;
}

.pcd-state-btn.running{
  color:#69b7ff;
  background:rgba(88,166,255,.14);
  border:1px solid rgba(88,166,255,.36);
}

.pcd-state-btn.completed{
  color:#00db72;
  background:rgba(0,219,114,.12);
  border:1px solid rgba(0,219,114,.35);
}

.pcd-state-btn.is-selected{
  box-shadow:0 0 0 2px rgba(255,255,255,.08), 0 0 12px rgba(88,166,255,.18);
}

/* ===== alarm ===== */
.log-card{
  margin-top:12px;
  border:1px solid rgba(255,255,255,.08);
  background:linear-gradient(180deg, rgba(18,24,34,.92), rgba(8,14,24,.95));
  border-radius:16px;
  overflow:hidden;
  box-shadow: inset 0 1px 0 rgba(255,255,255,.03), 0 10px 28px rgba(0,0,0,.28);
}

.log-top{
  display:flex;
  justify-content:space-between;
  align-items:center;
  padding:14px 16px;
  border-bottom:1px solid rgba(255,255,255,.08);
  gap:12px;
}

.log-title{
  font-size:15px;
  font-weight:900;
  letter-spacing:.8px;
  color:#dfe8ff;
  font-family:'Orbitron', "Segoe UI", system-ui, sans-serif;
}

.log-sub{
  margin-top:4px;
  font-size:11px;
  color:rgba(220,230,245,.72);
}

.log-actions{
  display:flex;
  align-items:center;
  gap:10px;
}

.log-badge{
  padding:8px 12px;
  border-radius:12px;
  border:1px solid rgba(255,255,255,.12);
  background:rgba(255,255,255,.06);
  font-size:12px;
  font-weight:800;
  color:#dfe8ff;
  white-space:nowrap;
}

.log-search{
  display:flex;
  align-items:center;
  gap:8px;
  padding:0 10px;
  min-width:220px;
  height:34px;
  border-radius:12px;
  background:rgba(255,255,255,.03);
  border:1px solid rgba(255,255,255,.10);
}

.log-search input{
  flex:1;
  background:transparent;
  border:none;
  outline:none;
  color:#dfe8ff;
  font-size:12px;
}

.log-search input::placeholder{
  color:rgba(220,230,245,.38);
}

.log-ic{
  color:rgba(220,230,245,.55);
  font-size:12px;
}

.log-head,
.log-row{
  display:grid;
  grid-template-columns: 1.1fr .8fr 1.6fr .8fr;
  align-items:center;
  column-gap:12px;
}

.log-head{
  padding:10px 14px;
  background:rgba(255,255,255,.06);
  font-size:11px;
  font-weight:800;
  text-transform:uppercase;
  letter-spacing:.6px;
  color:rgba(220,230,245,.72);
}

.log-body{
  max-height:260px;
  overflow:auto;
}

.log-row{
  padding:14px;
  border-top:1px solid rgba(255,255,255,.05);
  background:linear-gradient(90deg, rgba(87,166,255,.14) 0 4px, transparent 4px);
}

.log-time{
  display:flex;
  flex-direction:column;
  gap:4px;
  color:#dfe8ff;
  font-size:12px;
}

.log-time strong{
  font-size:14px;
  font-weight:800;
}

.log-code{
  font-size:13px;
  font-weight:800;
  color:#e8eefc;
}

.log-msg{
  display:flex;
  flex-direction:column;
  gap:4px;
}

.log-msg strong{
  font-size:14px;
  color:#f3f7ff;
}

.log-msg span{
  font-size:12px;
  color:rgba(220,230,245,.74);
}

.log-status{
  display:inline-flex;
  align-items:center;
  justify-content:center;
  min-width:88px;
  padding:8px 12px;
  border-radius:999px;
  font-size:11px;
  font-weight:800;
  letter-spacing:.7px;
}

.log-status.active{
  color:#ff6b73;
  background:rgba(255,69,79,.14);
  border:1px solid rgba(255,69,79,.45);
}

.log-status.clear{
  color:#00db72;
  background:rgba(0,219,114,.12);
  border:1px solid rgba(0,219,114,.35);
}

.log-foot{
  display:flex;
  justify-content:space-between;
  align-items:center;
  padding:10px 14px;
  border-top:1px solid rgba(255,255,255,.06);
  font-size:11px;
  color:rgba(220,230,245,.62);
}

/* ===== responsive ===== */
@media (max-width: 1400px){
  .bt-layout{
    grid-template-columns: 1.55fr 1fr;
  }

  .pcd-search{
    min-width:220px;
  }
}

@media (max-width: 1100px){
  .bt-layout{
    grid-template-columns:1fr;
  }

  .bt-detail-grid{
    grid-template-columns:1fr;
    height:auto;
  }

  .mini-chart{
    min-height:170px;
  }
}

.kpi-grey{
  border: 1px solid rgba(180,190,200,0.28) !important;
  background: linear-gradient(180deg, rgba(95,105,121,0.35), rgba(79,89,104,0.28)) !important;
  box-shadow: none !important;
}

.kpi-grey .kpi-label,
.kpi-grey .kpi-value,
.kpi-grey .kpi-unit{
  color: #e7ebf0 !important;
}

.panel-disabled {
  opacity: 0.45;
  pointer-events: none;
  position: relative;
}

/* optional overlay effect like main dashboard */
.panel-disabled::after {
  content: "";
  position: absolute;
  inset: 0;
  background: rgba(120, 130, 150, 0.15);
  border-radius: 12px;
}

options.onInit:
// Sets the text from customProperties
const htmlgraphicsText = htmlNode.getElementById('htmlgraphics-text');

if (htmlgraphicsText) {
  htmlgraphicsText.textContent = customProperties.text;

  // Change the text color based on the theme
  if (theme.isDark) {
    htmlgraphicsText.style.color = 'green';
  } else {
    htmlgraphicsText.style.color = 'red';
  }
}

options.onRender:
try {
  const root = htmlNode;

  function getGrafanaVariableValue(variable) {
    return getTemplateSrv().replace(variable);
  }

  const plantNo = String(getGrafanaVariableValue("${plantNo}") || "7");
  const btNo = String(getGrafanaVariableValue("${tankNo}") || "BT01");

  const seriesList = data?.series || [];
  const liveSeries = seriesList.find(s => String(s.refId).toUpperCase() === "A");
  const trendSeries = seriesList.find(s => String(s.refId).toUpperCase() === "B");

  const safeNum = (v, d = NaN) => {
    const n = Number(v);
    return Number.isFinite(n) ? n : d;
  };

  const setText = (sel, val) => {
    const el = root.querySelector(sel);
    if (el) el.textContent = val;
  };

  const defer = (fn) => setTimeout(fn, 50);

  function getField(series, name) {
    if (!series?.fields) return null;

    const target = String(name).toLowerCase();

    return series.fields.find(f => {
      const fieldName = String(f.name || "").toLowerCase();
      return (
        fieldName === target ||
        fieldName.endsWith("." + target) ||
        fieldName.includes(target)
      );
    }) || null;
  }
  function getFirst(series, fieldName, fallback = null) {
    const f = getField(series, fieldName);
    if (!f) return fallback;
    return f.values?.get ? f.values.get(0) : (f.values?.[0] ?? fallback);
  }

  function getArray(field) {
    if (!field) return [];
    if (field.values?.toArray) return field.values.toArray();
    if (field.values?.buffer) return Array.from(field.values.buffer);
    if (Array.isArray(field.values)) return field.values;
    if (field.values?.get) {
      const arr = [];
      const len = field.values.length ?? 0;
      for (let i = 0; i < len; i++) arr.push(field.values.get(i));
      return arr;
    }
    return [];
  }

  function pickTimeField(series) {
    if (!series?.fields) return null;

    let f = series.fields.find(x => String(x.name).toLowerCase() === "_time");
    if (f) return f;

    f = series.fields.find(x => String(x.name).toLowerCase() === "time");
    if (f) return f;

    f = series.fields.find(x => x.type === "time");
    if (f) return f;

    return null;
  }

  function renderMiniTrendWithAxis({ el, times = [], value = [], min = [], max = [], lastEl, unit = "" }) {
    if (!el) return;

    const N = Math.min(value.length, min.length, max.length, times.length);
    if (N < 2) {
      el.innerHTML = "";
      if (lastEl) lastEl.textContent = "--";
      return;
    }

    const tArr = times.slice(0, N);
    const vArr = value.slice(0, N).map(Number);
    const loArr = min.slice(0, N).map(Number);
    const hiArr = max.slice(0, N).map(Number);

    const W = el.clientWidth || 560;
    const H = el.clientHeight || 150;
    const padL = 46, padR = 12, padT = 10, padB = 24;
    const innerW = W - padL - padR;
    const innerH = H - padT - padB;

    let yMin = Math.min(...loArr.filter(Number.isFinite), ...vArr.filter(Number.isFinite));
    let yMax = Math.max(...hiArr.filter(Number.isFinite), ...vArr.filter(Number.isFinite));

    if (!Number.isFinite(yMin) || !Number.isFinite(yMax)) {
      el.innerHTML = "";
      if (lastEl) lastEl.textContent = "--";
      return;
    }

    if (yMin === yMax) {
      yMin -= 1;
      yMax += 1;
    }

    const pad = (yMax - yMin) * 0.06;
    yMin -= pad;
    yMax += pad;

    const x = (i) => padL + (i / (N - 1)) * innerW;
    const y = (val) => padT + (1 - (val - yMin) / (yMax - yMin)) * innerH;

    const fmtTime = (t) => {
      const d = new Date(t);
      if (isNaN(d.getTime())) return String(t);
      return d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
    };

    const buildPath = (arr) => {
      let d = "";
      for (let i = 0; i < N; i++) {
        const val = Number(arr[i]);
        if (!Number.isFinite(val)) continue;
        d += (d ? " L " : "M ") + `${x(i).toFixed(2)} ${y(val).toFixed(2)}`;
      }
      return d;
    };

    const lastVal = vArr[N - 1];
    if (lastEl) {
      lastEl.textContent = Number.isFinite(lastVal) ? `${lastVal.toFixed(2)}${unit}` : "--";
    }

    const yTicks = Array.from({ length: 5 }, (_, k) => yMin + (k / 4) * (yMax - yMin));
    const xIdx = [0, Math.floor((N - 1) / 2), N - 1];

    el.innerHTML = `
      <svg width="${W}" height="${H}" viewBox="0 0 ${W} ${H}" xmlns="http://www.w3.org/2000/svg">
        ${yTicks.map(tv => `
          <line x1="${padL}" y1="${y(tv)}" x2="${W - padR}" y2="${y(tv)}" stroke="rgba(255,255,255,0.08)" stroke-width="1"/>
          <text x="${padL - 8}" y="${y(tv) + 4}" text-anchor="end" fill="rgba(210,225,245,0.78)" font-size="10" font-weight="700">${tv.toFixed(2)}</text>
        `).join("")}

        <path d="${buildPath(loArr)}" fill="none" stroke="rgba(125,196,255,0.82)" stroke-width="1.7" stroke-dasharray="4 4"></path>
        <path d="${buildPath(hiArr)}" fill="none" stroke="rgba(125,196,255,0.82)" stroke-width="1.7" stroke-dasharray="4 4"></path>
        <path d="${buildPath(vArr)}" fill="none" stroke="rgba(88,166,255,0.95)" stroke-width="2.4"></path>

        ${xIdx.map(i => `
          <text x="${x(i)}" y="${H - 6}" text-anchor="middle" fill="rgba(210,225,245,0.78)" font-size="10" font-weight="700">${fmtTime(tArr[i])}</text>
        `).join("")}
      </svg>
    `;
  }

  function clearChart(chartSelector, lastSelector) {
    const chart = root.querySelector(chartSelector);
    if (chart) chart.innerHTML = "";
    const last = root.querySelector(lastSelector);
    if (last) last.textContent = "--";
  }

  function disableKpiCard(selector) {
    const el = root.querySelector(selector);
    const card = el ? el.closest(".kpi-card") : null;
    if (card) {
      card.classList.remove("kpi-green");
      card.classList.add("kpi-grey");
      card.style.opacity = "1";
    }
  }

  function disableKpiPanel(selector) {
    const el = root.querySelector(selector);
    const card = el ? el.closest(".kpi-card") : null;
    if (card) {
      card.classList.remove("kpi-green");
      card.classList.add("kpi-grey");
      card.classList.add("panel-disabled");
    }
  }

  function greyOutPanel(selector, opacity = "0.55") {
    const el = root.querySelector(selector);
    if (el) el.style.opacity = opacity;
  }

  // =========================
  // HEADER / TANK NAME
  // =========================
  setText("#tankName", btNo);

  // =========================
  // REAL LEVEL
  // =========================
  const levelField = getField(liveSeries, "level");
  const levelArr = getArray(levelField).map(Number).filter(Number.isFinite);
  const level = levelArr.length ? levelArr[levelArr.length - 1] : NaN;
  setText("#levelCm", Number.isFinite(level) ? level.toFixed(0) : "--");

  const tankFill = root.querySelector("#tankFill");
  if (tankFill) {
    const MAX_LEVEL = 460;
    const clamped = Number.isFinite(level) ? Math.max(0, Math.min(MAX_LEVEL, level)) : 0;
    const pct = (clamped / MAX_LEVEL) * 100;

    tankFill.style.height = `${pct.toFixed(1)}%`;
    tankFill.classList.remove("level-green", "level-yellow", "level-red");

    if (!Number.isFinite(level)) {
      tankFill.style.height = "0%";
    } else if (level > 80 && level < 460) {
      tankFill.classList.add("level-green");
    } else if (level <= 80) {
      tankFill.classList.add("level-red");
    } else {
      tankFill.classList.add("level-yellow");
    }
  }

  // =========================
  // GREY OUT QUALITY & INFO
  // =========================
  setText("#batchNo", "--");
  setText("#latexType", "--");
  setText("#supplyTank", "--");
  setText("#latexAge", "--");
  setText("#tsc", "--");
  setText("#stirrerHz", "--");

  disableKpiPanel("#batchNo");
  disableKpiPanel("#latexType");
  disableKpiPanel("#supplyTank");
  disableKpiPanel("#latexAge");
  disableKpiPanel("#tsc");
  disableKpiPanel("#stirrerHz");

  // =========================
  // DISABLE UNUSED CHARTS BUT KEEP DESIGN
  // =========================
  clearChart("#tscChartLeft", "#tscLastLeft");
  clearChart("#hzChartLeft", "#hzLastLeft");
  clearChart("#ageChart", "#ageLast");

  function disablePanel(chartSelector) {
    const chart = root.querySelector(chartSelector);
    if (!chart) return;

    const panel = chart.closest(".mini-trend");
    if (panel) {
      panel.classList.add("panel-disabled");
    }
  }

// Apply to trend panels
disablePanel("#tscChartLeft");
disablePanel("#hzChartLeft");
disablePanel("#ageChart");

 

  // =========================
  // REAL LEVEL TREND
  // =========================
  {
    const timeField = pickTimeField(trendSeries);
    const valueField =
      getField(trendSeries, "level") ||
      getField(trendSeries, "_value") ||   // ← ADD THIS HIGH PRIORITY
      getField(trendSeries, "mean") ||
      getField(trendSeries, "last");
    const times = getArray(timeField);
    const values = getArray(valueField).map(Number);

    const N = Math.min(times.length, values.length);
    const lo = Array.from({ length: N }, () => 0);
    const hi = Array.from({ length: N }, () => 460);

    if (N >= 2) {
      defer(() => renderMiniTrendWithAxis({
        el: root.querySelector("#levelChart"),
        times,
        value: values,
        min: lo,
        max: hi,
        lastEl: root.querySelector("#levelLast"),
        unit: " "
      }));
    } else {
      clearChart("#levelChart", "#levelLast");
    }
  }

  // =========================
  // GREY OUT BULK TANK STATUS TABLE
  // =========================
  const tableWrap = root.querySelector("#pcdTableWrap");
  if (tableWrap) {
    tableWrap.style.opacity = "0.55";
  }

  const tableRows = root.querySelectorAll(".pcd-item");
  tableRows.forEach(row => {
    row.setAttribute("data-batch", "--");
    row.setAttribute("data-type", "--");
    row.setAttribute("data-supply", "--");

    const cells = row.querySelectorAll(":scope > div");
    if (cells[0]) cells[0].textContent = "--";
    if (cells[1]) cells[1].textContent = "--";
    if (cells[2]) cells[2].textContent = "--";
    if (cells[3]) cells[3].innerHTML = `<span class="pcd-chipval">-- Hr</span>`;
    if (cells[4]) cells[4].innerHTML = `<span class="pcd-chipval">--%</span>`;
    if (cells[5]) cells[5].innerHTML = `<span class="pcd-chipval">--</span>`;
    if (cells[6]) cells[6].textContent = "--";

    const btn = row.querySelector(".pcd-state-btn");
    if (btn) {
      btn.textContent = "--";
      btn.classList.remove("running", "completed", "is-selected");
      btn.style.pointerEvents = "none";
      btn.style.opacity = "0.65";
    }
  });

  const searchBox = root.querySelector("#pcdSearchMain");
  if (searchBox) {
    searchBox.value = "";
    searchBox.disabled = true;
    searchBox.placeholder = "--";
  }

  // =========================
  // GREY OUT ALARM LOG
  // =========================
  const alarmCard = root.querySelector("#alarmCard");
  if (alarmCard) {
    alarmCard.style.opacity = "0.55";
  }

  setText("#alarmSub", "LEVEL ONLY");
  setText("#alarmBadge", "--");
  setText("#alarmFootLeft", "Last refresh: --");
  setText("#alarmFootRight", "Source: Level only");

  const alarmBody = root.querySelector("#alarmBody");
  if (alarmBody) {
    alarmBody.innerHTML = `
      <div class="log-row">
        <div class="log-time">
          <div>--</div>
          <strong>--</strong>
        </div>
        <div class="log-code">--</div>
        <div class="log-msg">
          <strong>--</strong>
          <span>--</span>
        </div>
        <div>
          <span class="log-status clear">--</span>
        </div>
      </div>
    `;
  }

  const alarmSearch = root.querySelector("#alarmSearch");
  if (alarmSearch) {
    alarmSearch.value = "";
    alarmSearch.disabled = true;
    alarmSearch.placeholder = "--";
  }

} catch (e) {
  console.log("Bulk Tank Dashboard OnRender error:", e);
}
